import 'server-only';

/* eslint-disable max-lines */

import type { Session } from 'next-auth';
import type { AuthRole, AuthUserAccessDetail, AuthUserPageSettings, AuthUserRoleMap } from '@/shared/contracts/auth';
import type { MongoSettingRecord } from '@/shared/contracts/base';
import { authError } from '@/shared/errors/app-error';
import { AUTH_SETTINGS_KEYS } from '@/shared/lib/auth/constants';
import { getMongoDb } from '@/shared/lib/db/mongo-client';
import { parseJsonSetting } from '@/shared/utils/settings-json';

const ROLE_ELEVATION_THRESHOLD = 90;
const AUTH_ACCESS_CACHE_TTL_MS = Number.parseInt(
  process.env['AUTH_ACCESS_CACHE_TTL_MS'] ?? process.env['AUTH_TOKEN_REFRESH_TTL_MS'] ?? '300000',
  10
);
const AUTH_SETTINGS_CACHE_TTL_MS = Number.parseInt(
  process.env['AUTH_SETTINGS_CACHE_TTL_MS'] ?? process.env['AUTH_ACCESS_CACHE_TTL_MS'] ?? '60000',
  10
);

const DEFAULT_AUTH_USER_PAGE_SETTINGS: AuthUserPageSettings = {
  allowSignup: true,
  allowPasswordReset: true,
  allowSocialLogin: true,
  requireEmailVerification: false,
};

type NormalizedAuthRole = AuthRole & {
  deniedPermissions: string[];
};

const DEFAULT_AUTH_ROLES: NormalizedAuthRole[] = [
  {
    id: 'super_admin',
    name: 'Super Admin',
    description: 'Full access to everything.',
    permissions: ['auth.users.read', 'auth.users.write', 'products.manage', 'notes.manage', 'chatbot.manage', 'ai_paths.manage', 'settings.manage', 'studiq.parent.access'],
    deniedPermissions: [],
    level: 100,
  },
  {
    id: 'superuser',
    name: 'Super User',
    description: 'Full access including system-level settings.',
    permissions: ['auth.users.read', 'auth.users.write', 'products.manage', 'notes.manage', 'chatbot.manage', 'ai_paths.manage', 'settings.manage', 'studiq.parent.access'],
    deniedPermissions: [],
    level: 95,
  },
  {
    id: 'admin',
    name: 'Admin',
    description: 'Full access to all apps and settings.',
    permissions: ['auth.users.read', 'auth.users.write', 'products.manage', 'notes.manage', 'chatbot.manage', 'ai_paths.manage', 'settings.manage', 'studiq.parent.access'],
    deniedPermissions: [],
    level: 90,
  },
  {
    id: 'viewer',
    name: 'Viewer',
    description: 'Read-only access.',
    permissions: ['auth.users.read'],
    deniedPermissions: [],
    level: 10,
  },
];

type MongoSettingDoc = Partial<MongoSettingRecord> & {
  updatedAt?: Date | string | null;
};

type AuthSettingsSnapshot = {
  roles: string | null;
  userRoles: string | null;
  defaultRole: string | null;
  userPages: string | null;
};

const parseCacheTtl = (value: number, fallback: number): number =>
  Number.isFinite(value) && value > 0 ? value : fallback;

const normalizeEmail = (email: string): string => email.trim().toLowerCase();

export const normalizeAuthEmail = normalizeEmail;

const getUpdatedAtMs = (value: Date | string | null | undefined): number | null => {
  if (value === null || value === undefined) return null;
  const parsed = value instanceof Date ? value.getTime() : Date.parse(value);
  return Number.isFinite(parsed) ? parsed : null;
};

const hasSettingValue = (doc: MongoSettingDoc): doc is MongoSettingDoc & { value: string } =>
  typeof doc.value === 'string';

const hasDocumentKey = (doc: MongoSettingDoc): boolean => {
  return typeof doc.key === 'string' && doc.key.trim() !== '';
};

const isMoreRecentSettingDoc = (
  candidate: MongoSettingDoc,
  selected: MongoSettingDoc
): boolean => {
  const candidateUpdated = getUpdatedAtMs(candidate.updatedAt);
  if (candidateUpdated === null) return false;

  const selectedUpdated = getUpdatedAtMs(selected.updatedAt);
  return selectedUpdated === null || candidateUpdated > selectedUpdated;
};

const pickPreferredSettingDoc = (docs: MongoSettingDoc[]): MongoSettingDoc | null => {
  return docs.filter(hasSettingValue).reduce<MongoSettingDoc | null>((selected, candidate) => {
    if (selected === null) {
      return candidate;
    }

    const candidateHasKey = hasDocumentKey(candidate);
    if (!candidateHasKey) return selected;

    if (hasDocumentKey(selected)) {
      return isMoreRecentSettingDoc(candidate, selected) ? candidate : selected;
    }

    return candidate;
  }, null);
};

const readMongoSettings = async (
  keys: readonly string[]
): Promise<Record<string, string | null>> => {
  const mongoDbUri = process.env['MONGODB_URI'];
  if (mongoDbUri === undefined || mongoDbUri === '') {
    return Object.fromEntries(keys.map((key) => [key, null]));
  }

  const mongo = await getMongoDb();
  const docs = await mongo
    .collection<MongoSettingDoc>('settings')
    .find(
      { $or: keys.flatMap((key) => [{ _id: key }, { key }]) },
      { projection: { _id: 1, key: 1, value: 1, updatedAt: 1 } }
    )
    .toArray();

  return Object.fromEntries(
    keys.map((key) => {
      const doc = pickPreferredSettingDoc(
        docs.filter((candidate) => candidate._id === key || candidate.key === key)
      );
      return [key, typeof doc?.value === 'string' ? doc.value : null];
    })
  );
};

let authSettingsSnapshotCache: { value: AuthSettingsSnapshot; ts: number } | null = null;
let authSettingsSnapshotInflight: Promise<AuthSettingsSnapshot> | null = null;

const getAuthSettingsSnapshot = async (): Promise<AuthSettingsSnapshot> => {
  const now = Date.now();
  const ttl = parseCacheTtl(AUTH_SETTINGS_CACHE_TTL_MS, 60_000);
  const currentSnapshot = authSettingsSnapshotCache;
  if (currentSnapshot !== null && now - currentSnapshot.ts < ttl) {
    return currentSnapshot.value;
  }
  if (authSettingsSnapshotInflight !== null) return authSettingsSnapshotInflight;

  const promise = (async (): Promise<AuthSettingsSnapshot> => {
    const values = await readMongoSettings([
      AUTH_SETTINGS_KEYS.roles,
      AUTH_SETTINGS_KEYS.userRoles,
      AUTH_SETTINGS_KEYS.defaultRole,
      AUTH_SETTINGS_KEYS.userPages,
    ]);

    return {
      roles: values[AUTH_SETTINGS_KEYS.roles] ?? null,
      userRoles: values[AUTH_SETTINGS_KEYS.userRoles] ?? null,
      defaultRole: values[AUTH_SETTINGS_KEYS.defaultRole] ?? null,
      userPages: values[AUTH_SETTINGS_KEYS.userPages] ?? null,
    };
  })();

  authSettingsSnapshotInflight = promise;
  try {
    const value = await promise;
    if (
      authSettingsSnapshotInflight === promise &&
      authSettingsSnapshotCache === currentSnapshot
    ) {
      authSettingsSnapshotCache = { value, ts: Date.now() };
    }
    return value;
  } finally {
    if (authSettingsSnapshotInflight === promise) {
      authSettingsSnapshotInflight = null;
    }
  }
};

const getDeniedPermissions = (fallback: AuthRole, role: AuthRole): string[] => {
  if (Array.isArray(role.deniedPermissions)) return role.deniedPermissions;
  if (Array.isArray(fallback.deniedPermissions)) return fallback.deniedPermissions;
  return [];
};

const mergeDefaultRoles = (roles: AuthRole[] | null | undefined): AuthRole[] => {
  const incoming = Array.isArray(roles) ? roles : [];
  const defaults = new Map<string, AuthRole>(DEFAULT_AUTH_ROLES.map((role) => [role.id, role]));
  const merged: NormalizedAuthRole[] = incoming.map((role) => {
    const fallback = defaults.get(role.id);
    if (!fallback) {
      return {
        ...role,
        permissions: Array.isArray(role.permissions) ? role.permissions : [],
        deniedPermissions: Array.isArray(role.deniedPermissions) ? role.deniedPermissions : [],
      } satisfies NormalizedAuthRole;
    }
    const deniedPermissions = getDeniedPermissions(fallback, role);
    return {
      ...fallback,
      ...role,
      permissions: Array.isArray(role.permissions) ? role.permissions : fallback.permissions,
      deniedPermissions,
      level: typeof role.level === 'number' ? role.level : fallback.level,
    } satisfies NormalizedAuthRole;
  });

  const known = new Set(merged.map((role) => role.id));
  for (const role of DEFAULT_AUTH_ROLES) {
    if (!known.has(role.id)) merged.push(role);
  }
  return merged;
};

const getAuthRoles = async (): Promise<AuthRole[]> => {
  const snapshot = await getAuthSettingsSnapshot();
  return mergeDefaultRoles(parseJsonSetting<AuthRole[]>(snapshot.roles, DEFAULT_AUTH_ROLES));
};

const getAuthUserRoles = async (): Promise<AuthUserRoleMap> => {
  const snapshot = await getAuthSettingsSnapshot();
  return parseJsonSetting<AuthUserRoleMap>(snapshot.userRoles, {});
};

const getAuthDefaultRoleId = async (): Promise<string | null> => {
  const snapshot = await getAuthSettingsSnapshot();
  const defaultRole = snapshot.defaultRole?.trim();
  return defaultRole === '' || defaultRole === undefined ? null : defaultRole;
};

export const getAuthUserPageSettings = async (): Promise<AuthUserPageSettings> => {
  const snapshot = await getAuthSettingsSnapshot();
  return parseJsonSetting<AuthUserPageSettings>(
    snapshot.userPages,
    DEFAULT_AUTH_USER_PAGE_SETTINGS
  );
};

const resolveEffectiveRole = (
  roleList: AuthRole[],
  userRoles: AuthUserRoleMap,
  userId: string,
  defaultRoleId: string | null
): { role: AuthRole; roleAssigned: boolean } => {
  const assignedRoleId = userRoles[userId];
  const assignedRole = roleList.find((role) => role.id === assignedRoleId);
  if (assignedRole) return { role: assignedRole, roleAssigned: true };

  const defaultRole =
    defaultRoleId !== null ? roleList.find((role) => role.id === defaultRoleId) : undefined;
  const fallbackRole =
    defaultRole ??
    roleList.find((role) => role.id === 'viewer') ??
    roleList[0] ??
    DEFAULT_AUTH_ROLES[0]!;

  return { role: fallbackRole, roleAssigned: false };
};

const accessCache = new Map<string, { value: AuthUserAccessDetail; ts: number }>();
const accessInflight = new Map<string, Promise<AuthUserAccessDetail>>();

export const invalidateAuthAccessCache = (userId?: string): void => {
  authSettingsSnapshotCache = null;
  authSettingsSnapshotInflight = null;
  if (userId !== undefined) {
    accessCache.delete(userId);
    accessInflight.delete(userId);
    return;
  }
  accessCache.clear();
  accessInflight.clear();
};

export const getAuthAccessForUser = async (userId: string): Promise<AuthUserAccessDetail> => {
  const now = Date.now();
  const ttl = parseCacheTtl(AUTH_ACCESS_CACHE_TTL_MS, 300_000);
  const cached = accessCache.get(userId);
  if (cached !== undefined && now - cached.ts < ttl) return cached.value;
  const inflight = accessInflight.get(userId);
  if (inflight !== undefined) return inflight;

  const promise = (async (): Promise<AuthUserAccessDetail> => {
    const [roles, userRoles, defaultRoleId] = await Promise.all([
      getAuthRoles(),
      getAuthUserRoles(),
      getAuthDefaultRoleId(),
    ]);
    const { role, roleAssigned } = resolveEffectiveRole(
      roles as Array<NormalizedAuthRole>,
      userRoles,
      userId,
      defaultRoleId
    );
    const deniedPermissions = (role as NormalizedAuthRole).deniedPermissions;
    const permissions = (role as NormalizedAuthRole).permissions.filter(
      (permission) => !deniedPermissions.includes(permission)
    );
    const level = role.level ?? 0;

    return {
      roleId: role.id,
      permissions,
      level,
      isElevated: level >= ROLE_ELEVATION_THRESHOLD,
      roleAssigned,
      role,
    };
  })();

  accessInflight.set(userId, promise);
  try {
    const value = await promise;
    accessCache.set(userId, { value, ts: Date.now() });
    return value;
  } finally {
    accessInflight.delete(userId);
  }
};

export async function readOptionalServerAuthSession(): Promise<Session | null> {
  const authModule = (await import('./auth')) as { auth: () => Promise<Session | null> };
  return authModule.auth();
}

export async function assertSettingsManageAccess(): Promise<void> {
  const session = await readOptionalServerAuthSession();
  const user = session?.user as
    | ({ isElevated?: boolean | null; permissions?: string[] | null } & Record<string, unknown>)
    | null
    | undefined;
  const userPermissions = user?.permissions ?? [];
  if (user?.isElevated === true || userPermissions.includes('settings.manage')) {
    return;
  }

  throw authError('Unauthorized.');
}

import {
  type DatabasePreviewGroup,
  type DatabasePreviewPayload,
  type DatabasePreviewRequest,
  type DatabasePreviewTable,
  type DatabaseTableDetail,
  type DatabaseTablePreviewData,
} from '@/shared/contracts/database';
import { type ApiPayloadResult } from '@/shared/contracts/http';
import { api, ApiError } from '@/shared/lib/api-client';
import { logClientError } from '@/shared/utils/observability/client-error-logger';
import { toFallbackErrorPayload } from './shared';

const normalizeStringRecord = (value: unknown): Record<string, unknown> =>
  value !== null && typeof value === 'object' && !Array.isArray(value)
    ? (value as Record<string, unknown>)
    : {};

const isRecordObject = (value: unknown): value is Record<string, unknown> =>
  value !== null && typeof value === 'object' && !Array.isArray(value);

const normalizeArray = <T>(value: unknown, isItem: (item: unknown) => item is T): T[] =>
  Array.isArray(value) ? value.filter(isItem) : [];

const normalizeStringArray = (value: unknown): string[] =>
  normalizeArray(value, (item): item is string => typeof item === 'string');

const normalizeRecordArray = (value: unknown): Record<string, unknown>[] =>
  normalizeArray(value, isRecordObject);

const toDatabaseSizeString = (value: unknown): string => {
  if (typeof value === 'string') {
    return value;
  }
  if (typeof value === 'number') {
    return String(value);
  }
  return '';
};

const parsePositiveInt = (rawValue: unknown, fallback: number): number => {
  if (typeof rawValue === 'number') {
    return Number.isFinite(rawValue) && rawValue > 0 ? rawValue : fallback;
  }

  if (typeof rawValue === 'string') {
    const parsed = Number.parseInt(rawValue, 10);
    return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
  }

  return fallback;
};

const parseTotal = (primary: unknown, fallback: unknown): number => {
  if (typeof primary === 'number' && Number.isFinite(primary)) {
    return primary;
  }

  if (typeof fallback === 'number' && Number.isFinite(fallback)) {
    return fallback;
  }

  return 0;
};

const firstStringValue = (values: unknown[]): string => {
  const found = values.find(
    (value): value is string => typeof value === 'string' && value.length > 0
  );
  return found ?? '';
};

const getRawPayload = (raw: Record<string, unknown>): Record<string, unknown> => {
  const rawData = raw['data'];
  if (rawData !== null && typeof rawData === 'object') {
    return normalizeStringRecord(rawData);
  }

  return raw;
};

const normalizeGroups = (data: unknown): DatabasePreviewGroup[] => {
  if (!Array.isArray(data)) return [];

  return data
    .filter((group): group is Record<string, unknown> => group !== null && typeof group === 'object')
    .map((group) => {
      const type = group['type'];
      return {
        type: firstStringValue([type, group['name']]),
        objects: normalizeStringArray(group['objects'] ?? group['tables']),
      };
    });
};

export const getDatabasePreview = async (
  input: DatabasePreviewRequest
): Promise<ApiPayloadResult<DatabasePreviewPayload>> => {
  try {
    const raw = await api.post<Record<string, unknown>>('/api/databases/preview', input);
    const normalized = getRawPayload(raw);
    const rawStats = normalizeStringRecord(normalized['stats']);

    const groups = normalizeGroups(normalized['groups'] ?? rawStats['groups']);
    const tables = normalizeRecordArray(normalized['tables']) as DatabasePreviewTable[];
    const tableRows = normalizeRecordArray(normalized['tableRows']) as DatabaseTablePreviewData[];
    const tableDetails = normalizeRecordArray(normalized['tableDetails']) as DatabaseTableDetail[];
    const total = normalized['total'];
    const totalRows = rawStats['total'];
    const finalPage = normalized['page'] ?? input.page;
    const finalPageSize = normalized['pageSize'] ?? input.pageSize;
    const databaseSize = toDatabaseSizeString(normalized['databaseSize']);

    const payload: DatabasePreviewPayload = {
      groups,
      tables,
      tableRows,
      tableDetails,
      databaseSize,
      total: parseTotal(total, totalRows),
      page: parsePositiveInt(finalPage, input.page ?? 1),
      pageSize: parsePositiveInt(finalPageSize, input.pageSize ?? 20),
    };

    return { ok: true, payload };
  } catch (error) {
    logClientError(error);
    if (error instanceof ApiError) {
      if (error.payload !== undefined && error.payload !== null) {
        return { ok: false, payload: error.payload as DatabasePreviewPayload };
      }
      return { ok: false, payload: toFallbackErrorPayload(error) };
    }
    return { ok: false, payload: toFallbackErrorPayload(error) };
  }
};

export const fetchDatabasePreview = getDatabasePreview;

'use client';

import React, { useMemo, useState } from 'react';

import type { ModalStateProps } from '@/shared/contracts/ui/base';
import { SettingsPanelBuilder } from '@/shared/ui/templates/SettingsPanelBuilder';
import type { SettingsPanelField } from '@/shared/contracts/ui/settings';

interface RestoreModalProps extends ModalStateProps {
  backupName: string;
  onConfirm: (truncate: boolean) => void;
  title?: string;
  size?: 'sm' | 'md' | 'lg' | 'xl';
}

type RestoreFormState = {
  truncate: boolean;
};

export const RestoreModal = ({
  isOpen,
  onClose,
  onSuccess,
  backupName,
  onConfirm,
  title = 'Restore Database',
  size = 'sm',
}: RestoreModalProps): React.JSX.Element | null => {
  const [values, setValues] = useState<RestoreFormState>({ truncate: true });

  const fields = useMemo<SettingsPanelField<RestoreFormState>[]>(
    () => [
      {
        key: 'truncate',
        label: 'Confirmation',
        type: 'custom',
        render: () => (
          <p className='text-gray-300'>
            Are you sure you want to restore backup <strong>{backupName}</strong>?
          </p>
        ),
      },
      {
        key: 'truncate',
        label: 'Truncate (delete) existing data before restore',
        type: 'checkbox',
      },
    ],
    [backupName]
  );

  const handleSave = async (): Promise<void> => {
    onConfirm(values.truncate);
    onSuccess?.();
  };

  return (
    <SettingsPanelBuilder
      open={isOpen}
      onClose={onClose}
      title={title}
      fields={fields}
      values={values}
      onChange={(vals) => setValues((prev) => ({ ...prev, ...vals }))}
      onSave={handleSave}
      saveText='Restore'
      size={size}
    />
  );
};

'use client';

import Link from 'next/link';
import {
  CloudUploadIcon,
  DatabaseIcon,
  DownloadIcon,
  PencilIcon,
  PowerIcon,
  RefreshCwIcon,
} from 'lucide-react';
import type { JSX } from 'react';

import type {
  DatabaseEngineManagedMongoApplication,
  DatabaseEngineManagedMongoApplicationTarget,
  DatabaseEngineManagedMongoCollectionStats,
  DatabaseEngineManagedMongoDatabase,
  DatabaseEngineManagedMongoDatabasesResponse,
  DatabaseEngineManagedMongoEndpoint,
  DatabaseEngineMongoPendingSyncRequest,
  MongoSource,
} from '@/shared/contracts/database';
import { StatusBadge } from '@/shared/ui/data-display.public';
import { Button, Card } from '@/shared/ui/primitives.public';
import { buildManagedMongoCrudHref } from '../crud/ManagedMongoScopePanel';

const SOURCE_LABELS: Record<MongoSource, string> = {
  local: 'Local',
  cloud: 'Cloud',
};

export const isPendingSyncTarget = (
  pendingSync: DatabaseEngineMongoPendingSyncRequest | null,
  direction: 'cloud_to_local' | 'local_to_cloud',
  application: DatabaseEngineManagedMongoApplicationTarget
): boolean =>
  pendingSync !== null &&
  pendingSync.direction === direction &&
  pendingSync.application === application;

export const formatBytes = (bytes: number | null): string => {
  if (bytes === null) return 'n/a';
  if (bytes < 1024) return `${bytes} B`;
  const units = ['KB', 'MB', 'GB', 'TB'];
  let value = bytes / 1024;
  let unitIndex = 0;
  while (value >= 1024 && unitIndex < units.length - 1) {
    value /= 1024;
    unitIndex += 1;
  }
  return `${value.toFixed(value >= 10 ? 1 : 2)} ${units[unitIndex]}`;
};

const getEndpointStatus = (
  endpoint: DatabaseEngineManagedMongoEndpoint
): { status: string; variant: 'active' | 'error' | 'pending' } => {
  if (!endpoint.configured) return { status: 'Not configured', variant: 'pending' };
  if (endpoint.reachable === true) return { status: 'Reachable', variant: 'active' };
  if (endpoint.reachable === false) return { status: 'Unreachable', variant: 'error' };
  return { status: 'Unknown', variant: 'pending' };
};

export function CollectionSizeList({
  collections,
}: {
  collections: DatabaseEngineManagedMongoCollectionStats[];
}): JSX.Element {
  if (collections.length === 0) {
    return <p className='text-xs text-gray-400'>No collection stats available.</p>;
  }

  return (
    <div className='max-h-52 overflow-auto rounded-md border border-white/10'>
      <table className='w-full text-left text-[11px]'>
        <thead className='sticky top-0 bg-gray-950 text-gray-400'>
          <tr>
            <th className='px-2 py-1.5 font-medium'>Collection</th>
            <th className='px-2 py-1.5 text-right font-medium'>Docs</th>
            <th className='px-2 py-1.5 text-right font-medium'>Size</th>
          </tr>
        </thead>
        <tbody>
          {collections.map((collection) => (
            <tr key={collection.name} className='border-t border-white/10 text-gray-300'>
              <td className='max-w-40 truncate px-2 py-1.5 font-mono' title={collection.name}>
                {collection.name}
              </td>
              <td className='px-2 py-1.5 text-right'>
                {collection.documentCount?.toLocaleString() ?? 'n/a'}
              </td>
              <td className='px-2 py-1.5 text-right'>
                {formatBytes(collection.totalSizeBytes)}
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export function EndpointPanel({
  endpoint,
}: {
  endpoint: DatabaseEngineManagedMongoEndpoint;
}): JSX.Element {
  const status = getEndpointStatus(endpoint);

  return (
    <div className='space-y-3 rounded-md border border-white/10 bg-black/20 p-3'>
      <div className='flex items-start justify-between gap-2'>
        <div className='space-y-1'>
          <h4 className='text-xs font-semibold uppercase text-gray-300'>
            {SOURCE_LABELS[endpoint.source]}
          </h4>
          <p className='text-xs text-gray-400'>{endpoint.dbName ?? 'No database selected'}</p>
        </div>
        <StatusBadge status={status.status} variant={status.variant} size='sm' />
      </div>

      <div className='space-y-1 text-xs text-gray-300'>
        <p className='truncate' title={endpoint.maskedUri ?? ''}>
          {endpoint.maskedUri ?? 'No URI configured'}
        </p>
        <p>Database size: {formatBytes(endpoint.databaseSizeBytes)}</p>
        <p>Collections: {endpoint.collectionCount.toLocaleString()}</p>
        <p>Collection storage: {formatBytes(endpoint.collectionsSizeBytes)}</p>
        {endpoint.healthError !== null && endpoint.healthError !== '' ? <p className='text-rose-200'>{endpoint.healthError}</p> : null}
      </div>

      <CollectionSizeList collections={endpoint.collections} />
    </div>
  );
}

export function ManagedDatabaseCardHeader({
  database,
}: {
  database: DatabaseEngineManagedMongoDatabase;
}): JSX.Element {
  return (
    <div className='space-y-1'>
      <h3 className='flex items-center gap-2 text-sm font-semibold text-white'>
        <DatabaseIcon className='size-4 text-emerald-200' />
        {database.label}
      </h3>
      {database.syncIssue !== null && database.syncIssue !== '' && (
        <p className='text-xs leading-relaxed text-amber-100'>{database.syncIssue}</p>
      )}
      {database.syncDisabled && (
        <p className='text-xs leading-relaxed text-sky-100'>
          Sync disabled
          {database.syncDisabledReason !== null && database.syncDisabledReason !== ''
            ? `: ${database.syncDisabledReason}`
            : '.'}
        </p>
      )}
    </div>
  );
}

export function ManagedDatabaseCardActions({
  database,
  isBackupDisabled,
  isPushDisabled,
  isPullDisabled,
  isPushing,
  isPulling,
  isTogglingSync,
  backupManagedMongo,
  setManagedMongoSyncDisabled,
  syncManagedMongo,
}: {
  database: DatabaseEngineManagedMongoDatabase;
  isBackupDisabled: boolean;
  isPushDisabled: boolean;
  isPullDisabled: boolean;
  isPushing: boolean;
  isPulling: boolean;
  isTogglingSync: boolean;
  backupManagedMongo: (application: DatabaseEngineManagedMongoApplicationTarget) => Promise<void> | void;
  setManagedMongoSyncDisabled: (
    application: DatabaseEngineManagedMongoApplication,
    disabled: boolean
  ) => Promise<void> | void;
  syncManagedMongo: (
    direction: 'local_to_cloud' | 'cloud_to_local',
    application: DatabaseEngineManagedMongoApplicationTarget
  ) => Promise<void> | void;
}): JSX.Element {
  return (
    <div className='flex flex-wrap gap-2'>
      <Button asChild type='button' variant='outline' size='sm'>
        <Link href={buildManagedMongoCrudHref(database.application, 'local')}>
