import { type NextRequest, NextResponse } from 'next/server';

import { cancelProductAiJob, getProductAiJob } from '@/features/database/server/jobs';
import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import { badRequestError, notFoundError } from '@/shared/errors/app-error';
import { assertDatabaseEngineManageAccess } from '@/features/database/server';
import { assertDatabaseEngineOperationEnabled } from '@/shared/lib/db/services/database-engine-operation-guards';

type DatabaseEngineCancelableJob = {
  productId?: string | null | undefined;
  jobType: string;
};

const isDatabaseEngineCancelableJob = (value: unknown): value is DatabaseEngineCancelableJob => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return false;
  const record = value as Record<string, unknown>;
  const productId = record['productId'];
  return (
    (typeof productId === 'string' || productId === null || productId === undefined) &&
    typeof record['jobType'] === 'string'
  );
};

const isDatabaseEngineOperationJob = (job: DatabaseEngineCancelableJob): boolean =>
  job.productId === 'system' && job.jobType === 'db_backup';

export async function postHandler(
  _req: NextRequest,
  _ctx: ApiHandlerContext,
  params: { jobId: string }
): Promise<Response> {
  await assertDatabaseEngineManageAccess();

  await assertDatabaseEngineOperationEnabled('allowOperationJobCancellation');

  const { jobId } = params;
  if (!jobId) {
    throw badRequestError('Job id is required.');
  }

  const job = await getProductAiJob(jobId);
  if (!job) {
    throw notFoundError('Job not found.', { jobId });
  }
  if (!isDatabaseEngineCancelableJob(job) || !isDatabaseEngineOperationJob(job)) {
    throw badRequestError('Only Database Engine db_backup jobs can be cancelled.', {
      jobId,
      productId: job['productId'],
      type: job['jobType'],
    });
  }

  const cancelled = await cancelProductAiJob(jobId);

  return NextResponse.json(
    {
      success: true,
      job: cancelled,
    },
    { headers: { 'Cache-Control': 'no-store' } }
  );
}

import { type NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import { getProductAiJobs, getQueueStatus } from '@/features/database/server/jobs';
import type {
  DatabaseEngineOperationJob,
  DatabaseEngineOperationsJobs,
} from '@/shared/contracts/database';
import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import { optionalIntegerQuerySchema } from '@/shared/lib/api/query-schema';
import { assertDatabaseEngineManageAccess } from '@/features/database/server';

export const querySchema = z.object({
  limit: optionalIntegerQuerySchema(z.number().int().min(1).max(200)),
});

type DatabaseEngineOperationJobRecord = Awaited<ReturnType<typeof getProductAiJobs>>[number];

const isDatabaseEngineOperationJob = (job: DatabaseEngineOperationJobRecord): boolean =>
  job.jobType === 'db_backup';

const toOperationJob = (job: DatabaseEngineOperationJobRecord): DatabaseEngineOperationJob => {
  const payload =
    job.payload && typeof job.payload === 'object'
      ? (job.payload as Record<string, unknown>)
      : null;
  const result = job.result && typeof job.result === 'object' ? job.result : null;

  const rawDbType = payload?.['dbType'];
  const dbType =
    rawDbType === 'mongodb' ? (rawDbType as DatabaseEngineOperationJob['dbType']) : null;
  const direction = null;
  const source = typeof payload?.['source'] === 'string' ? payload['source'] : null;
  const resultSummary =
    typeof result?.['message'] === 'string'
      ? result['message']
      : typeof result?.['warning'] === 'string'
        ? result['warning']
        : null;

  let status: DatabaseEngineOperationJob['status'] = 'queued';
  if (job.status === 'running') status = 'running';
  if (job.status === 'completed') status = 'completed';
  if (job.status === 'failed') status = 'failed';
  if (job.status === 'canceled' || job.status === 'cancelled') status = 'canceled';

  return {
    id: job.id,
    type: (job.jobType ?? 'db_backup') as DatabaseEngineOperationJob['type'],
    status,
    dbType,
    direction,
    source,
    createdAt: new Date(job.createdAt || Date.now()).toISOString(),
    updatedAt:
      typeof job.updatedAt === 'string' && job.updatedAt.length > 0
        ? new Date(job.updatedAt).toISOString()
        : null,
    startedAt: typeof job.startedAt === 'string' && job.startedAt.length > 0 ? job.startedAt : null,
    finishedAt:
      typeof job.finishedAt === 'string' && job.finishedAt.length > 0 ? job.finishedAt : null,
    errorMessage: job.errorMessage ?? null,
    resultSummary,
    payload: payload ?? {},
    result: result ?? null,
    progress: job.progress ?? 0,
    completedAt: job.completedAt ?? null,
  };
};

export async function getHandler(_req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  await assertDatabaseEngineManageAccess();

  const query = (_ctx.query ?? {}) as z.infer<typeof querySchema>;
  const limit = query.limit ?? 30;
  const [jobsResponse, queueStatus] = await Promise.all([
    getProductAiJobs('system'),
    getQueueStatus(),
  ]);

  const jobs = jobsResponse
    .filter(isDatabaseEngineOperationJob)
    .slice(0, limit)
    .map(toOperationJob);

  const payload: DatabaseEngineOperationsJobs = {
    timestamp: new Date().toISOString(),
    queueStatus,
    jobs,
  };

  return NextResponse.json(payload, {
    headers: { 'Cache-Control': 'no-store' },
  });
}

import { type NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import {
  databaseEngineManagedMongoApplicationSchema,
  mongoSourceSchema,
} from '@/shared/contracts/database';
import { badRequestError, forbiddenError } from '@/shared/errors/app-error';
import { parseJsonBody } from '@/shared/lib/api/parse-json';
import { getMongoClient } from '@/shared/lib/db/mongo-client';
import { createManagedMongoClient } from '@/shared/lib/db/services/managed-mongo-databases';
import { assertDatabaseEngineManageAccess } from '@/features/database/server';
import { ErrorSystem } from '@/shared/utils/observability/error-system';


const MONGO_COLLECTION_NAME_MAX_LENGTH = 255;
const isValidMongoCollectionName = (value: string): boolean => {
  if (value.length === 0 || value.length > MONGO_COLLECTION_NAME_MAX_LENGTH) return false;
  if (value.includes('\0') || value.includes('$')) return false;
  return !value.startsWith('system.');
};
const collectionNameSchema = z
  .string()
  .trim()
  .min(1, 'Collection name is required.')
  .max(MONGO_COLLECTION_NAME_MAX_LENGTH, 'Collection name is too long.')
  .refine(isValidMongoCollectionName, 'Valid MongoDB collection name is required.');

const databaseExecuteRequestSchema = z.object({
  sql: z.string().trim().min(1).optional(),
  type: z.enum(['mongodb', 'auto']).optional().default('auto'),
  application: databaseEngineManagedMongoApplicationSchema.optional(),
  source: mongoSourceSchema.optional(),
  collection: collectionNameSchema.optional(),
  operation: z
    .enum(['find', 'insertOne', 'updateOne', 'deleteOne', 'deleteMany', 'aggregate', 'countDocuments'])
    .optional(),
  filter: z.record(z.string(), z.unknown()).optional(),
  document: z.record(z.string(), z.unknown()).optional(),
  update: z.record(z.string(), z.unknown()).optional(),
  pipeline: z.array(z.record(z.string(), z.unknown())).optional(),
  skip: z.number().int().min(0).optional(),
  limit: z.number().int().min(1).max(500).optional(),
  sort: z.record(z.string(), z.union([z.literal(1), z.literal(-1)])).optional(),
});

export async function postHandler(req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  await assertDatabaseEngineManageAccess();
  if (process.env['NODE_ENV'] === 'production') {
    throw forbiddenError('Database operations are disabled in production.');
  }

  const parsedBody = await parseJsonBody(req, databaseExecuteRequestSchema, {
    logPrefix: 'database-engine-web.databases.execute',
  });
  if (!parsedBody.ok) {
    return parsedBody.response;
  }

  const parsed = parsedBody.data;
  if (parsed.sql) {
    throw badRequestError('SQL execution is no longer supported. Use MongoDB collection operations.');
  }
  if (!parsed.collection) {
    throw badRequestError('Collection name is required for MongoDB operations.');
  }

  try {
    return await handleMongoOperation(parsed);
  } catch (error) {
    void ErrorSystem.captureException(error);
    try {
      const { ErrorSystem } = await import('@/shared/lib/observability/system-logger');
      void ErrorSystem.captureException(error, {
        service: 'api/databases/execute',
        provider: 'mongodb',
        collection: parsed.collection,
      });
    } catch (error) {
      void ErrorSystem.captureException(error);

      // Ignore error capture failures
    }
    throw error;
  }
}

async function handleMongoOperation(parsed: {
  collection?: string;
  operation?: string;
  application?: z.infer<typeof databaseEngineManagedMongoApplicationSchema>;
  source?: z.infer<typeof mongoSourceSchema>;
  filter?: Record<string, unknown>;
  document?: Record<string, unknown>;
  update?: Record<string, unknown>;
  pipeline?: Record<string, unknown>[];
  skip?: number;
  limit?: number;
  sort?: Record<string, 1 | -1>;
}): Promise<Response> {
  const {
    collection: collName,
    operation,
    application,
    source,
    filter,
    document,
    update,
    pipeline,
    skip,
    limit,
    sort,
  } = parsed;

  if (!collName) {
    throw badRequestError('Collection name is required for MongoDB operations.');
  }
  if (!operation) {
    throw badRequestError('Operation is required for MongoDB operations.');
  }

  const managedMongo = application
    ? await createManagedMongoClient(application, source ?? 'local')
    : null;
  const mongoClient = managedMongo?.client ?? (await getMongoClient());
  const dbName = managedMongo?.dbName ?? process.env['MONGODB_DB'] ?? 'stardb';
  const db = managedMongo?.db ?? mongoClient.db(dbName);
  const collection = db.collection(collName);
  const startTime = Date.now();

  let result: unknown;
  let rowCount: number;

  try {
    switch (operation) {
      case 'find': {
        const resolvedSkip = Math.max(0, skip ?? 0);
        const resolvedLimit = Math.min(500, Math.max(1, limit ?? 200));
        const resolvedFilter = filter ?? {};
        const [docs, totalCount] = await Promise.all([
          collection
            .find(resolvedFilter)
            .sort(sort ?? { _id: 1 })
            .skip(resolvedSkip)
            .limit(resolvedLimit)
            .toArray(),
          collection.countDocuments(resolvedFilter),
        ]);
        result = docs;
        rowCount = totalCount;
        break;
      }
      case 'insertOne': {
        if (!document) {
          throw badRequestError('Document is required for insertOne.');
        }
        const insertResult = await collection.insertOne(document);
        result = [{ insertedId: insertResult.insertedId }];
        rowCount = insertResult.acknowledged ? 1 : 0;
        break;
      }
      case 'updateOne': {
        if (!update) {
          throw badRequestError('Update object is required for updateOne.');
        }
        const updateResult = await collection.updateOne(filter ?? {}, update);
        result = [
          { matchedCount: updateResult.matchedCount, modifiedCount: updateResult.modifiedCount },
        ];
        rowCount = updateResult.modifiedCount;
        break;
      }
      case 'deleteOne': {
        const deleteResult = await collection.deleteOne(filter ?? {});
        result = [{ deletedCount: deleteResult.deletedCount }];
        rowCount = deleteResult.deletedCount;
        break;
      }
      case 'deleteMany': {
        const deleteManyResult = await collection.deleteMany(filter ?? {});
        result = [{ deletedCount: deleteManyResult.deletedCount }];
        rowCount = deleteManyResult.deletedCount;
        break;
      }
      case 'countDocuments': {
        const count = await collection.countDocuments(filter ?? {});
        result = [{ count }];
        rowCount = 1;
        break;
      }
      case 'aggregate': {
        if (!pipeline) {
          throw badRequestError('Pipeline is required for aggregate.');
        }
        const aggDocs = await collection.aggregate(pipeline).toArray();
        result = aggDocs;
        rowCount = aggDocs.length;
        break;
      }
      default:
        throw badRequestError(`Unsupported operation: ${operation}`);
    }
  } finally {
    if (managedMongo !== null) {
      await managedMongo.client.close().catch(() => undefined);
    }
  }

  const duration = Date.now() - startTime;
  return NextResponse.json({
    rows: Array.isArray(result) ? result : [],
    rowCount,
    fields: [],
    command: operation,
    executionTimeMs: duration,
  });
}

import { type NextRequest, NextResponse } from 'next/server';
import { MongoClient, type Collection, type Db } from 'mongodb';
import { z } from 'zod';

import {
  databaseEngineManagedMongoApplicationSchema,
  mongoSourceSchema,
  type DatabaseColumnInfo,
  type DatabaseIndexInfo,
  type DatabaseTableDetail,
} from '@/shared/contracts/database';
import {
  ensureMongoBackupsDir,
  assertValidMongoBackupName,
  getMongoBackupApplication,
  getArchMongoConnectionUrl,
  getArchMongoDatabaseName,
  getMongoConnectionUrl,
  getMongoDatabaseName,
  getMongoRestoreCommand,
  getCmsBuilderMongoConnectionUrl,
  getCmsBuilderMongoDatabaseName,
  getEcommerceMongoConnectionUrl,
  getEcommerceMongoDatabaseName,
  getStudiqMongoConnectionUrl,
  getStudiqMongoDatabaseName,
  mongoExecFileAsync,
  resolveMongoBackupPath,
} from '@/features/database/server';
import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import { badRequestError, internalError } from '@/shared/errors/app-error';
import { parseObjectJsonBody } from '@/shared/lib/api/parse-json';
import { assertDatabaseEngineManageAccess } from '@/features/database/server';
import { createManagedMongoClient } from '@/shared/lib/db/services/managed-mongo-databases';
import { ErrorSystem } from '@/shared/utils/observability/error-system';

const resolvePreviewTarget = (
  previewMode: 'backup' | 'current',
  backupName: string | undefined
): { mongoUri: string; sourceDbName: string } => {
  if (previewMode === 'backup' && backupName) {
    const application = getMongoBackupApplication(backupName);
    if (application === 'studiq') {
      return {
        mongoUri: getStudiqMongoConnectionUrl(),
        sourceDbName: getStudiqMongoDatabaseName(),
      };
    }
    if (application === 'cms-builder') {
      return {
        mongoUri: getCmsBuilderMongoConnectionUrl(),
        sourceDbName: getCmsBuilderMongoDatabaseName(),
      };
    }
    if (application === 'products') {
      return {
        mongoUri: getEcommerceMongoConnectionUrl(),
        sourceDbName: getEcommerceMongoDatabaseName(),
      };
    }
    if (application === 'arch') {
      return {
        mongoUri: getArchMongoConnectionUrl(),
        sourceDbName: getArchMongoDatabaseName(),
      };
    }
  }

  return {
    mongoUri: getMongoConnectionUrl(),
    sourceDbName: getMongoDatabaseName(),
  };
};

const getFieldType = (value: unknown): string => {
  if (value === null) return 'null';
  if (Array.isArray(value)) return 'array';
  if (value instanceof Date) return 'date';
  if (
    typeof value === 'object' &&
    value !== null &&
    (value as { constructor?: { name?: string } }).constructor?.name === 'ObjectId'
  ) {
    return 'ObjectId';
  }
  return typeof value;
};

const getNumber = (value: unknown): number | null => {
  if (typeof value !== 'number' || !Number.isFinite(value)) return null;
  return Math.max(0, value);
};

const sumNullableNumbers = (...values: Array<number | null>): number | null => {
  const finiteValues = values.filter((value): value is number => value !== null);
  if (finiteValues.length === 0) return null;
  return finiteValues.reduce((sum, value) => sum + value, 0);
};

const formatBytes = (bytes: number | null): string => {
  if (bytes === null) return 'n/a';
  if (bytes < 1024) return `${bytes} B`;
  const units = ['KB', 'MB', 'GB', 'TB'];
  let value = bytes / 1024;
  let unitIndex = 0;
  while (value >= 1024 && unitIndex < units.length - 1) {
    value /= 1024;
    unitIndex += 1;
  }
  return `${value.toFixed(value >= 10 ? 1 : 2)} ${units[unitIndex]}`;
};

const getDatabaseSizeFormatted = async (db: Db): Promise<string> => {
  try {
    const stats = (await db.command({ dbStats: 1, scale: 1 })) as Record<string, unknown>;
    const storageSizeBytes = getNumber(stats['storageSize']);
    const indexSizeBytes = getNumber(stats['indexSize']);
    const databaseSizeBytes =
      getNumber(stats['totalSize']) ?? sumNullableNumbers(storageSizeBytes, indexSizeBytes);
    return formatBytes(databaseSizeBytes);
  } catch (error) {
    void ErrorSystem.captureException(error, {
      service: 'api/databases/preview',
      stage: 'database-stats',
    });
    return 'n/a';
  }
};

const getCollectionSizeFormatted = async (
  db: Db,
  collectionName: string
): Promise<string> => {
  try {
    const stats = (await db.command({
      collStats: collectionName,
      scale: 1,
    })) as Record<string, unknown>;
    const storageSizeBytes = getNumber(stats['storageSize']);
    const indexSizeBytes = getNumber(stats['totalIndexSize']);
    const collectionSizeBytes =
      getNumber(stats['totalSize']) ?? sumNullableNumbers(storageSizeBytes, indexSizeBytes);
    return formatBytes(collectionSizeBytes);
  } catch (error) {
    void ErrorSystem.captureException(error, {
      service: 'api/databases/preview',
      stage: 'collection-stats',
      collectionName,
    });
    return 'n/a';
  }
};

const buildIndexDefinition = (index: Record<string, unknown>): string | undefined => {
  const key = index['key'];
  if (typeof key !== 'object' || key === null || Array.isArray(key)) return undefined;

  return Object.entries(key)
    .map(([column, direction]) => `${column}: ${String(direction)}`)
    .join(', ');
};

const getCollectionIndexes = async (
  collection: Collection
): Promise<DatabaseIndexInfo[]> => {
  try {
    const indexes = (await collection.indexes()) as Array<Record<string, unknown>>;
    return indexes
      .map((index) => {
        const key = index['key'];
        const columns =
          typeof key === 'object' && key !== null && !Array.isArray(key)
            ? Object.keys(key)
            : [];
        const fallbackName = columns.length > 0 ? columns.join('_') : 'index';
        const name = typeof index['name'] === 'string' ? index['name'] : fallbackName;

        return {
          name,
          columns,
          isUnique: index['unique'] === true,
          definition: buildIndexDefinition(index),
        };
      })
      .sort((a, b) => {
        if (a.name === '_id_') return -1;
        if (b.name === '_id_') return 1;
        return a.name.localeCompare(b.name);
      });
  } catch (error) {
    void ErrorSystem.captureException(error, {
      service: 'api/databases/preview',
      stage: 'collection-indexes',
      collectionName: collection.collectionName,
    });
    return [];
  }
};

const buildTableDetail = (
  collectionName: string,
  sample: Record<string, unknown>[],
  indexes: DatabaseIndexInfo[],
  rowEstimate: number,
  sizeFormatted: string
): DatabaseTableDetail => {
  const fieldTypes = new Map<string, Set<string>>();
  for (const doc of sample) {
    for (const [key, value] of Object.entries(doc)) {
      if (!fieldTypes.has(key)) fieldTypes.set(key, new Set<string>());
      fieldTypes.get(key)?.add(getFieldType(value));
    }
  }

  const fields: DatabaseColumnInfo[] = [...fieldTypes.entries()]
    .map(([name, types]) => ({
      name,
      type: [...types].join(' | ') || 'unknown',
      nullable: types.has('null'),
      defaultValue: null,
      isPrimaryKey: name === '_id',
      isForeignKey: false,
    }))
    .sort((a, b) => {
      if (a.name === '_id') return -1;
      if (b.name === '_id') return 1;
      return a.name.localeCompare(b.name);
    });

  return {
    name: collectionName,
    columns: fields,
    indexes,
    foreignKeys: [],
    rowEstimate,
    sizeFormatted,
  };
};

export async function postDatabasesPreviewHandler(
  req: NextRequest,
  _ctx: ApiHandlerContext
): Promise<Response> {
  await assertDatabaseEngineManageAccess();

  const parsed = await parseObjectJsonBody(req, {
    logPrefix: 'database-engine-web.databases.preview',
  });
  if (!parsed.ok) {
    return parsed.response;
  }

  const body = z
    .object({
      backupName: z.string().optional(),
      mode: z.enum(['backup', 'current']).optional(),
      type: z.enum(['mongodb']).optional(),
      page: z.number().optional(),
      pageSize: z.number().optional(),
      application: databaseEngineManagedMongoApplicationSchema.optional(),
      source: mongoSourceSchema.optional(),
    })
    .parse(parsed.data);

  const previewMode = body.mode === 'current' ? 'current' : 'backup';
  const previewType = body.type ?? 'mongodb';
  const backupName = body.backupName;

  if (previewType !== 'mongodb') {
    throw badRequestError('Only MongoDB previews are supported.');
  }
  if (previewMode === 'backup' && !backupName) {
    throw badRequestError('Backup name is required');
  }
  if (previewMode === 'backup') {
    assertValidMongoBackupName(backupName ?? '');
    await ensureMongoBackupsDir();
  }

  const requestedApplication = body.application;
  const requestedSource = (body.source ?? 'local');
  const usesManagedCurrent = previewMode === 'current' && requestedApplication !== undefined;
  const target = usesManagedCurrent ? null : resolvePreviewTarget(previewMode, backupName);
  const mongoUri = target?.mongoUri ?? '';
  const sourceDbName = target?.sourceDbName ?? '';
  const previewDb = previewMode === 'backup' ? `stardb_preview_${Date.now()}` : sourceDbName;
  const page = Math.max(1, Number.isFinite(body.page) ? Number(body.page) : 1);
  const pageSize = Math.min(
    200,
    Math.max(1, Number.isFinite(body.pageSize) ? Number(body.pageSize) : 20)
  );
  const offset = (page - 1) * pageSize;

  if (previewMode === 'backup') {
    const backupPath = await resolveMongoBackupPath(backupName ?? '');
    try {
      await mongoExecFileAsync(getMongoRestoreCommand(), [
        '--uri',
        mongoUri,
        `--archive=${backupPath}`,
        '--gzip',
        '--nsFrom',
        `${sourceDbName}.*`,
        '--nsTo',
        `${previewDb}.*`,
        '--drop',
      ]);
    } catch (error) {
      void ErrorSystem.captureException(error);
      const message = error instanceof Error ? error.message : 'Unknown error';
      throw internalError(`Failed to inspect backup: ${message}`);
    }
  }

  const managedMongo =
    usesManagedCurrent && requestedApplication
      ? await createManagedMongoClient(requestedApplication, requestedSource)
      : null;
  const mongoClient = managedMongo?.client ?? new MongoClient(mongoUri);
  if (managedMongo === null) {
    await mongoClient.connect();
  }
  const db = managedMongo?.db ?? mongoClient.db(previewDb);
  let collections: string[] = [];
  let tableRows: { name: string; rows: Record<string, unknown>[]; totalRows: number }[] = [];
  let tableStats: { name: string; rowEstimate: number; sizeFormatted: string }[] = [];
  let tableDetails: DatabaseTableDetail[] = [];
  let databaseSize = 'n/a';

  try {
    const [databaseSizeResult, collectionInfos] = await Promise.all([
      getDatabaseSizeFormatted(db),
      db.listCollections().toArray(),
    ]);
    databaseSize = databaseSizeResult;
    collections = collectionInfos
      .map((info: { name: string }) => info.name)
      .sort((a, b) => a.localeCompare(b));

    tableRows = await Promise.all(
      collections.map(async (collectionName: string) => {
        const collection = db.collection(collectionName);
        const totalRows = await collection.countDocuments();
        const rows = await collection.find({}).skip(offset).limit(pageSize).toArray();
        return { name: collectionName, rows: rows as Record<string, unknown>[], totalRows };
      })
    );

    tableStats = await Promise.all(
      collections.map(async (collectionName: string) => {
        const collection = db.collection(collectionName);
        const [estimate, sizeFormatted] = await Promise.all([
          collection.estimatedDocumentCount(),
          getCollectionSizeFormatted(db, collectionName),
        ]);
        return { name: collectionName, rowEstimate: estimate, sizeFormatted };
      })
    );
    tableDetails = await Promise.all(
      collections.map(async (collectionName: string) => {
        const collection = db.collection(collectionName);
        const [sample, indexes] = await Promise.all([
          collection.find({}).limit(10).toArray() as Promise<Record<string, unknown>[]>,
          getCollectionIndexes(collection),
        ]);
        const collectionStats = tableStats.find((table) => table.name === collectionName);
        return buildTableDetail(
          collectionName,
          sample,
          indexes,
          collectionStats?.rowEstimate ?? 0,
          collectionStats?.sizeFormatted ?? 'n/a'
        );
      })
    );
  } finally {
    if (previewMode === 'backup') {
      try {
        await db.dropDatabase();
      } catch (error) {
        void ErrorSystem.captureException(error);
        void ErrorSystem.captureException(error, {
          service: 'api/databases/preview',
          stage: 'cleanup-preview-db',
          previewDb,
        });
      }
    }
    await mongoClient.close();
  }

  return NextResponse.json({
    stats: {
      tables: tableStats,
      groups: collections.length > 0 ? { COLLECTION: collections } : {},
    },
    data: tableRows,
    tableDetails,
    databaseSize,
    page,
    pageSize,
  });
}

import { type NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import type { RedisOverview } from '@/shared/contracts/database';
import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import { optionalIntegerQuerySchema } from '@/shared/lib/api/query-schema';
import { assertDatabaseEngineManageAccess } from '@/features/database/server';
import { getRedisClient } from '@/shared/lib/redis';
import { ErrorSystem } from '@/shared/utils/observability/error-system';


export const querySchema = z.object({
  limit: optionalIntegerQuerySchema(z.number().int().min(20).max(2000)),
  count: optionalIntegerQuerySchema(z.number().int().min(20).max(1000)),
});

const parseInfoValue = (info: string, key: string): string | null => {
  const row = info
    .split('\n')
    .map((line: string) => line.trim())
    .find((line: string) => line.startsWith(`${key}:`));
  if (!row) return null;
  return row.slice(key.length + 1) || null;
};

const getNamespace = (key: string): string => {
  const idx = key.indexOf(':');
  if (idx <= 0) return '(root)';
  return key.slice(0, idx);
};

export async function getHandler(_req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  await assertDatabaseEngineManageAccess();
  const query = (_ctx.query ?? {}) as z.infer<typeof querySchema>;
  const client = getRedisClient();
  if (!client) {
    const disabled: RedisOverview = {
      enabled: false,
      connected: false,
      urlConfigured: Boolean(process.env['REDIS_URL']),
      dbSize: 0,
      usedMemory: null,
      maxMemory: null,
      namespaces: [],
      sampleKeys: [],
      status: 'disabled',
      version: 'n/a',
      keysCount: 0,
      memoryUsed: '0',
      uptime: '0',
      clients: 0,
    };
    return NextResponse.json(disabled, {
      headers: { 'Cache-Control': 'no-store' },
    });
  }

  const limit = query.limit ?? 200;
  const count = query.count ?? 200;

  let connected: boolean;
  try {
    await client.ping();
    connected = true;
  } catch (error) {
    void ErrorSystem.captureException(error);
    connected = false;
  }

  const dbSize = connected ? await client.dbsize().catch(() => 0) : 0;
  const memoryInfo = connected ? await client.info('memory').catch(() => '') : '';
  const usedMemory = parseInfoValue(memoryInfo, 'used_memory_human');
  const maxMemory = parseInfoValue(memoryInfo, 'maxmemory_human');

  const keys: string[] = [];
  if (connected) {
    let cursor = '0';
    do {
      const response = await client.scan(cursor, 'COUNT', String(count));
      const batch = response[1] ?? [];
      keys.push(...batch);
      cursor = response[0] ?? '0';
      if (keys.length >= limit) break;
    } while (cursor !== '0');
  }

  const cappedKeys = keys.slice(0, limit);
  const namespaceMap = new Map<string, { keyCount: number; sampleKeys: string[] }>();
  cappedKeys.forEach((key: string) => {
    const namespace = getNamespace(key);
    const current = namespaceMap.get(namespace) ?? { keyCount: 0, sampleKeys: [] };
    current.keyCount += 1;
    if (current.sampleKeys.length < 5) {
      current.sampleKeys.push(key);
    }
    namespaceMap.set(namespace, current);
  });

  const namespaces = Array.from(namespaceMap.entries())
    .map(([namespace, stats]) => ({
      namespace,
      keyCount: stats.keyCount,
      sampleKeys: stats.sampleKeys,
    }))
    .sort((a, b) => b.keyCount - a.keyCount || a.namespace.localeCompare(b.namespace));

  const payload: RedisOverview = {
    enabled: true,
    connected,
    urlConfigured: Boolean(process.env['REDIS_URL']),
    dbSize,
    usedMemory,
    maxMemory,
    namespaces,
    sampleKeys: cappedKeys.slice(0, 25),
  };

  return NextResponse.json(payload, {
    headers: { 'Cache-Control': 'no-store' },
  });
}

import { promises as fs } from 'fs';
import path from 'path';

import { type NextRequest, NextResponse } from 'next/server';
import { MongoClient } from 'mongodb';
import { z } from 'zod';

import {
  ensureMongoBackupsDir,
  assertValidMongoBackupName,
  getMongoBackupApplication,
  getArchMongoConnectionUrl,
  getArchMongoDatabaseName,
  getMongoConnectionUrl,
  getMongoDatabaseName,
  getMongoRestoreCommand,
  getCmsBuilderMongoConnectionUrl,
  getCmsBuilderMongoDatabaseName,
  getEcommerceMongoConnectionUrl,
  getEcommerceMongoDatabaseName,
  getStudiqMongoConnectionUrl,
  getStudiqMongoDatabaseName,
  mongoExecFileAsync,
  resolveMongoBackupPath,
} from '@/features/database/server';
import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import { badRequestError, internalError } from '@/shared/errors/app-error';
import { parseObjectJsonBody } from '@/shared/lib/api/parse-json';
import { normalizeOptionalQueryString } from '@/shared/lib/api/query-schema';
import { assertDatabaseEngineManageAccess } from '@/features/database/server';
import { assertDatabaseEngineOperationEnabled } from '@/shared/lib/db/services/database-engine-operation-guards';
import { ErrorSystem } from '@/shared/utils/observability/error-system';


type ExecOutputishError = {
  stdout?: string;
  stderr?: string;
  cause?: {
    stdout?: string;
    stderr?: string;
  };
};

export const querySchema = z.object({
  type: z.preprocess(
    (value: unknown) => normalizeOptionalQueryString(value),
    z.enum(['mongodb']).optional()
  ),
});

const resolveRestoreTarget = (backupName: string): { mongoUri: string; databaseName: string } => {
  const application = getMongoBackupApplication(backupName);
  if (application === 'studiq') {
    return {
      mongoUri: getStudiqMongoConnectionUrl(),
      databaseName: getStudiqMongoDatabaseName(),
    };
  }

  if (application === 'cms-builder') {
    return {
      mongoUri: getCmsBuilderMongoConnectionUrl(),
      databaseName: getCmsBuilderMongoDatabaseName(),
    };
  }

  if (application === 'products') {
    return {
      mongoUri: getEcommerceMongoConnectionUrl(),
      databaseName: getEcommerceMongoDatabaseName(),
    };
  }

  if (application === 'arch') {
    return {
      mongoUri: getArchMongoConnectionUrl(),
      databaseName: getArchMongoDatabaseName(),
    };
  }

  return {
    mongoUri: getMongoConnectionUrl(),
    databaseName: getMongoDatabaseName(),
  };
};

export async function postDatabasesRestoreHandler(
  req: NextRequest,
  _ctx: ApiHandlerContext
): Promise<Response> {
  await assertDatabaseEngineManageAccess();
  await assertDatabaseEngineOperationEnabled('allowManualBackupMaintenance');

  let stage = 'validate';

  const query = (_ctx.query ?? {}) as z.infer<typeof querySchema>;
  const type = query.type ?? 'mongodb';
  if (type !== 'mongodb') {
    throw badRequestError('Only MongoDB restores are supported.');
  }

  const parsed = await parseObjectJsonBody(req, {
    logPrefix: 'database-engine-web.databases.restore',
  });
  if (!parsed.ok) {
    return parsed.response;
  }

  const body = z
    .object({
      backupName: z.string(),
      truncateBeforeRestore: z.boolean().optional(),
    })
    .parse(parsed.data);

  const backupName = body.backupName;
  const truncateBeforeRestore = Boolean(body.truncateBeforeRestore);
  if (!backupName) {
    throw badRequestError('Backup name is required');
  }

  assertValidMongoBackupName(backupName);
  await ensureMongoBackupsDir();

  const backupPath = await resolveMongoBackupPath(backupName);
  const { mongoUri, databaseName } = resolveRestoreTarget(backupName);

  if (truncateBeforeRestore) {
    const mongoClient = new MongoClient(mongoUri);
    try {
      await mongoClient.connect();
      const db = mongoClient.db(databaseName);
      const collections = await db.listCollections().toArray();

      for (const collection of collections) {
        await db.collection(collection.name).drop();
      }
    } finally {
      await mongoClient.close();
    }
  }

  stage = 'mongorestore';
  const logPath = `${backupPath}.restore.log`;
  const command = getMongoRestoreCommand();
  const args = [
    '--uri',
    mongoUri,
    '--db',
    databaseName,
    `--archive=${backupPath}`,
    '--gzip',
    '--drop',
  ];
  const commandString = `${command} ${args.join(' ')}`;

  let stdout = '';
  let stderr = '';

  try {
    const result = await mongoExecFileAsync(command, args);
    stdout = result.stdout;
    stderr = result.stderr;
  } catch (error) {
    void ErrorSystem.captureException(error);
    const err = error as ExecOutputishError;
    stdout = err.stdout ?? err.cause?.stdout ?? '';
    stderr = err.stderr ?? err.cause?.stderr ?? '';

    const logContent = `command:\n${commandString}\n\nstdout:\n${stdout}\n\nstderr:\n${stderr}`;
    await fs.writeFile(logPath, logContent);
    throw internalError('Failed to restore backup', {
      stage,
      backupName,
      log: logContent,
    });
  }

  const logContent = `command:\n${commandString}\n\nstdout:\n${stdout}\n\nstderr:\n${stderr}`;
  await fs.writeFile(logPath, logContent);

  stage = 'log';
  const restoreLogPath = path.join(path.dirname(backupPath), 'restore-log.json');
  let logData: Record<string, { date: string; logFile: string }> = {};

  try {
    const logFile = await fs.readFile(restoreLogPath, 'utf-8');
    logData = JSON.parse(logFile) as Record<string, { date: string; logFile: string }>;
  } catch (error) {
    void ErrorSystem.captureException(error);
    const { ErrorSystem: SystemLogger } = await import('@/shared/lib/observability/system-logger');
    void SystemLogger.logWarning('Failed to load restore-log.json', { error, stage, backupName });
  }

  logData[backupName] = {
    date: new Date().toISOString(),
    logFile: `${backupName}.restore.log`,
  };

  await fs.writeFile(restoreLogPath, JSON.stringify(logData, null, 2));

  return NextResponse.json({
    message: 'Backup restored',
    log: logContent,
  });
}

import { type NextRequest, NextResponse } from 'next/server';
import { z } from 'zod';

import type {
  CollectionSchema,
  FieldInfo,
  SchemaProvider,
  SchemaResponse,
} from '@/shared/contracts/database';
import type { ApiHandlerContext } from '@/shared/contracts/ui/api';
import {
  normalizeOptionalQueryString,
  optionalBooleanQuerySchema,
} from '@/shared/lib/api/query-schema';
import { getMongoDb } from '@/shared/lib/db/mongo-client';
import {
  assertDatabaseEngineManageAccessOrAiPathsInternal,
  isCollectionAllowed,
} from '@/features/database/server';
import { ErrorSystem } from '@/shared/utils/observability/error-system';


const MONGO_SCHEMA_CONCURRENCY = 8;

export const querySchema = z.object({
  provider: z.preprocess(
    (value: unknown) => normalizeOptionalQueryString(value)?.toLowerCase(),
    z.enum(['auto', 'all', 'mongodb']).optional()
  ),
  includeCounts: optionalBooleanQuerySchema(),
});

const toSchemaSource = (schema: SchemaResponse): Record<string, unknown> => ({
  provider: schema.provider,
  collections: schema.collections,
  ...(schema.sources ? { sources: schema.sources } : {}),
});

async function mapWithConcurrency<T, R>(
  items: T[],
  concurrency: number,
  worker: (item: T, index: number) => Promise<R>
): Promise<R[]> {
  if (items.length === 0) return [];
  const safeConcurrency = Math.max(1, Math.min(concurrency, items.length));
  const results: Array<R | null> = Array.from({ length: items.length }, () => null);
  let nextIndex = 0;

  const runWorker = async (): Promise<void> => {
    while (true) {
      const currentIndex = nextIndex;
      nextIndex += 1;
      if (currentIndex >= items.length) return;
      const item = items[currentIndex]!;
      results[currentIndex] = await worker(item, currentIndex);
    }
  };

  await Promise.all(Array.from({ length: safeConcurrency }, () => runWorker()));
  return results.map((value: R | null): R => {
    if (value === null) {
      throw new Error('Schema concurrency mapping produced an incomplete result.');
    }
    return value;
  });
}

async function getMongoSchema(includeCounts = false): Promise<SchemaResponse> {
  const db = await getMongoDb();
  const collectionInfos = (await db.listCollections().toArray()).filter(
    (info) => !info.name.startsWith('system.')
  );
  const collections = await mapWithConcurrency(
    collectionInfos,
    MONGO_SCHEMA_CONCURRENCY,
    async (info) => {
      const collName = info.name;
      const coll = db.collection(collName);
      const sample = await coll.find({}).limit(10).toArray();

      const fieldTypes = new Map<string, Set<string>>();

      for (const doc of sample) {
        for (const [key, value] of Object.entries(doc)) {
          if (!fieldTypes.has(key)) {
            fieldTypes.set(key, new Set());
          }
          const typeSet = fieldTypes.get(key)!;
          if (value === null) {
            typeSet.add('null');
          } else if (Array.isArray(value)) {
            typeSet.add('array');
          } else if (value instanceof Date) {
            typeSet.add('date');
          } else if (
            typeof value === 'object' &&
            (value as { constructor?: { name?: string } })?.constructor?.name === 'ObjectId'
          ) {
            typeSet.add('ObjectId');
          } else {
            typeSet.add(typeof value);
          }
        }
      }

      const fields: FieldInfo[] = [];
      for (const [name, types] of fieldTypes) {
        const typeArray = Array.from(types);
        const fieldType =
          typeArray.length === 1 ? (typeArray[0] ?? 'unknown') : typeArray.join(' | ');
        const fieldInfo: FieldInfo = {
          name,
          type: fieldType,
        };
        if (name === '_id') {
          fieldInfo.isId = true;
        }
        fields.push(fieldInfo);
      }

      fields.sort((a: FieldInfo, b: FieldInfo) => {
        if (a.name === '_id') return -1;
        if (b.name === '_id') return 1;
        return a.name.localeCompare(b.name);
      });

      const entry: CollectionSchema = { name: collName, fields };

      if (includeCounts) {
        try {
          entry.documentCount = await coll.estimatedDocumentCount();
        } catch (error) {
          void ErrorSystem.captureException(error);

          // Best-effort count only.
        }
      }

      return entry;
    }
  );

  collections.sort((a: CollectionSchema, b: CollectionSchema) => a.name.localeCompare(b.name));
  return { provider: 'mongodb', collections };
}

const enrichCollections = (
  schema: SchemaResponse,
  provider: SchemaProvider
): Array<CollectionSchema & { provider: SchemaProvider }> => {
  const collections: CollectionSchema[] = Array.isArray(schema.collections)
    ? schema.collections
    : Object.values(schema.collections as Record<string, CollectionSchema>);

  return collections.map((collection: CollectionSchema) => ({
    ...collection,
    provider,
  }));
};

const filterCollectionsToAiPathsAllowlist = (schema: SchemaResponse): SchemaResponse => {
  const filteredCollections = schema.collections.filter((collection: CollectionSchema) =>
    isCollectionAllowed(collection.name)
  );

  return {
    ...schema,
    collections: filteredCollections,
  };
};

export async function getDatabasesSchemaHandler(
  request: NextRequest,
  _ctx: ApiHandlerContext
): Promise<Response> {
  const { isInternal } = await assertDatabaseEngineManageAccessOrAiPathsInternal(request);
  const query = (_ctx.query ?? {}) as z.infer<typeof querySchema>;
  const providerParam = query.provider ?? 'auto';
  const includeCounts = query.includeCounts === true;

  if (providerParam === 'all') {
    const mongoSchema = await getMongoSchema(includeCounts);
    const visibleMongoSchema = isInternal
      ? filterCollectionsToAiPathsAllowlist(mongoSchema)
      : mongoSchema;
    const payload: SchemaResponse = {
      provider: 'multi',
      collections: enrichCollections(visibleMongoSchema, 'mongodb'),
      sources: {
        mongodb: toSchemaSource(visibleMongoSchema),
      },
    };
    return NextResponse.json(payload);
  }

  const schema = await getMongoSchema(includeCounts);
  const visibleSchema = isInternal ? filterCollectionsToAiPathsAllowlist(schema) : schema;
  return NextResponse.json(visibleSchema);
}

import 'server-only';

import {
  createMongoBackup,
  createMongoManagedBackup,
} from '@/shared/lib/db/services/database-backup';
import {
  markDatabaseBackupJobFailed,
  markDatabaseBackupJobRunning,
  markDatabaseBackupJobSucceeded,
} from '@/shared/lib/db/services/database-backup-scheduler';
import type { DatabaseEngineManagedMongoApplicationTarget } from '@/shared/contracts/database';
import type {
  ProductAiJob,
  ProductAiJobRecord,
  ProductAiJobType,
  ProductAiJobUpdate,
} from '@/shared/contracts/jobs';
import { operationFailedError } from '@/shared/errors/app-error';
import { getProductAiJobRepository } from '@/shared/lib/products/services/product-ai-job-repository';
import { createManagedQueue } from '@/shared/lib/queue';
import { ErrorSystem } from '@/shared/utils/observability/error-system';
import { isObjectRecord } from '@/shared/utils/object-utils';

type ProductAiJobWithProduct = Omit<ProductAiJob, 'product'> & {
  product: Record<string, unknown> | null;
};

type DatabaseBackupQueueJobData = {
  jobId: string;
  productId: string;
  type: string;
  payload: unknown;
};

const DATABASE_BACKUP_QUEUE_NAME = 'product-ai';
const DATABASE_BACKUP_JOB_TIMEOUT_MS = (() => {
  const raw = Number.parseInt(process.env['DATABASE_ENGINE_BACKUP_JOB_TIMEOUT_MS'] ?? '', 10);
  if (!Number.isFinite(raw)) return 30 * 60 * 1000;
  return Math.max(5 * 60 * 1000, raw);
})();
const DATABASE_BACKUP_RUNNING_STALE_TTL_MS = (() => {
  const raw = Number.parseInt(
    process.env['DATABASE_ENGINE_BACKUP_RUNNING_STALE_TTL_MS'] ?? '',
    10
  );
  if (!Number.isFinite(raw)) return 10 * 60 * 1000;
  return Math.max(60 * 1000, raw);
})();

let backupJobRecoveryInFlight = false;

const isManagedMongoApplicationTarget = (
  value: unknown
): value is DatabaseEngineManagedMongoApplicationTarget =>
  value === 'all' ||
  value === 'geminitestapp' ||
  value === 'studiq' ||
  value === 'cms-builder' ||
  value === 'products' ||
  value === 'arch';

const resolveManagedBackupApplication = (
  payload: unknown
): DatabaseEngineManagedMongoApplicationTarget | null => {
  if (!isObjectRecord(payload)) return null;
  const directApplication = payload['application'];
  if (isManagedMongoApplicationTarget(directApplication)) return directApplication;
  const managedApplication = payload['managedApplication'];
  if (isManagedMongoApplicationTarget(managedApplication)) return managedApplication;
  return null;
};

const toIsoString = (value?: Date | null): string | null => {
  if (!value) return null;
  return value.toISOString();
};

const toJobResult = (value: unknown): Record<string, unknown> | null => {
  if (value === null || value === undefined) return null;
  return isObjectRecord(value) ? value : null;
};

const toProductAiJob = (record: ProductAiJobRecord): ProductAiJob => ({
  id: record.id,
  productId: record.productId,
  status: record.status === 'canceled' ? 'cancelled' : record.status,
  type: record.type,
  jobType: record.type as ProductAiJobType,
  payload: isObjectRecord(record.payload) ? record.payload : undefined,
  result: toJobResult(record.result),
  errorMessage: record.errorMessage ?? null,
  error: record.errorMessage ?? null,
  createdAt: record.createdAt.toISOString(),
  updatedAt: record.updatedAt.toISOString(),
  startedAt: toIsoString(record.startedAt),
  finishedAt: toIsoString(record.finishedAt),
  completedAt: toIsoString(record.finishedAt),
});

const toJobUpdate = (data: ProductAiJobUpdate): ProductAiJobUpdate => data;

const markBackupRunningSafely = async (jobId: string): Promise<void> => {
  try {
    await markDatabaseBackupJobRunning('mongodb', jobId);
  } catch (error) {
    await ErrorSystem.captureException(error);
  }
};

const markBackupSucceededSafely = async (jobId: string): Promise<void> => {
  try {
    await markDatabaseBackupJobSucceeded('mongodb', jobId);
  } catch (error) {
    await ErrorSystem.captureException(error);
  }
};

const markBackupFailedSafely = async (jobId: string, message: string): Promise<void> => {
  try {
    await markDatabaseBackupJobFailed('mongodb', jobId, message);
  } catch (error) {
    await ErrorSystem.captureException(error);
  }
};

export async function enqueueProductAiJob(
  productId: string,
  type: ProductAiJobType,
  payload: unknown
): Promise<ProductAiJob> {
  const repository = await getProductAiJobRepository();
  const record = await repository.createJob(productId, type, payload);
  return toProductAiJob(record);
}

export async function getProductAiJobs(
  productId?: string
): Promise<ProductAiJobWithProduct[]> {
  const repository = await getProductAiJobRepository();
  const records = await repository.findJobs(productId);
  return records.map((record) => ({
    ...toProductAiJob(record),
    product: null,
  }));
}

export async function getProductAiJob(jobId: string): Promise<ProductAiJobWithProduct | null> {
  const repository = await getProductAiJobRepository();
  const record = await repository.findJobById(jobId);
  if (!record) return null;
  return {
    ...toProductAiJob(record),
    product: null,
  };
}

export async function cancelProductAiJob(jobId: string): Promise<ProductAiJob> {
  const repository = await getProductAiJobRepository();
  const updated = await repository.updateJob(
    jobId,
    toJobUpdate({
      status: 'canceled',
      finishedAt: new Date(),
      errorMessage: 'Cancelled by Database Engine.',
    })
  );
  return toProductAiJob(updated);
}

const runBackupForJob = async (record: ProductAiJobRecord) => {
  const managedApplication = resolveManagedBackupApplication(record.payload);
  if (managedApplication !== null) {
    return createMongoManagedBackup(managedApplication);
  }
  return createMongoBackup();
};

const isStaleRunningBackupJob = (record: ProductAiJobRecord, nowMs: number): boolean => {
  if (record.status !== 'running') return false;
  const startedAtMs = record.startedAt instanceof Date ? record.startedAt.getTime() : Number.NaN;
  if (!Number.isFinite(startedAtMs)) return true;
  return nowMs - startedAtMs >= DATABASE_BACKUP_RUNNING_STALE_TTL_MS;
};

const recoverInterruptedBackupJobs = async (): Promise<void> => {
  if (backupJobRecoveryInFlight) return;
  backupJobRecoveryInFlight = true;

  try {
    const repository = await getProductAiJobRepository();
    const [pending, running] = await Promise.all([
      repository.findJobs('system', { type: 'db_backup', statuses: ['pending'] }),
      repository.findJobs('system', { type: 'db_backup', statuses: ['running'] }),
    ]);
    const nowMs = Date.now();
    const jobsToRecover = [
      ...pending,
      ...running.filter((record) => isStaleRunningBackupJob(record, nowMs)),
    ];

    for (const record of jobsToRecover) {
      await enqueueProductAiJobToQueue(record.id, record.productId, record.type, record.payload);
    }
  } catch (error) {
    await ErrorSystem.captureException(error, {
      service: 'database-engine-db-backup-queue',
      action: 'recoverInterruptedBackupJobs',
    });
  } finally {
    backupJobRecoveryInFlight = false;
  }
};

export async function processProductAiJob(jobId: string): Promise<ProductAiJob> {
  const repository = await getProductAiJobRepository();
  const record = await repository.findJobById(jobId);
  if (!record) {
    throw operationFailedError('Job not found.', undefined, { jobId });
  }
  if (record.type !== 'db_backup') {
    throw operationFailedError('Standalone Database Engine can only process db_backup jobs.', undefined, {
      jobId,
      type: record.type,
    });
  }

  await markBackupRunningSafely(jobId);
  await repository.updateJob(
    jobId,
    toJobUpdate({
      status: 'running',
      startedAt: new Date(),
      errorMessage: null,
    })
  );

  try {
    const result = await runBackupForJob(record);
    await markBackupSucceededSafely(jobId);
    const updated = await repository.updateJob(
      jobId,
      toJobUpdate({
        status: 'completed',
        result: { ...result, dbType: 'mongodb' },
        finishedAt: new Date(),
        errorMessage: null,
      })
    );
    return toProductAiJob(updated);
  } catch (error) {
    await ErrorSystem.captureException(error);
    const message = error instanceof Error ? error.message : String(error);
    await markBackupFailedSafely(jobId, message);
    await repository.updateJob(
      jobId,
      toJobUpdate({
        status: 'failed',
        finishedAt: new Date(),
        errorMessage: message,
      })
    );
    throw error;
  }
}

const queue = createManagedQueue<DatabaseBackupQueueJobData>({
  name: DATABASE_BACKUP_QUEUE_NAME,
  concurrency: 1,
  jobTimeoutMs: DATABASE_BACKUP_JOB_TIMEOUT_MS,
  defaultJobOptions: {
    attempts: 1,
    removeOnComplete: true,
    removeOnFail: false,
  },
  processor: async (data) => processProductAiJob(data.jobId),
  onFailed: async (_queueJobId, error, data) => {
    const message = error instanceof Error ? error.message : String(error);
    await markBackupFailedSafely(data.jobId, message);
  },
});

export function startProductAiJobQueue(): void {
  queue.startWorker();
  void recoverInterruptedBackupJobs();
}

export async function enqueueProductAiJobToQueue(
  jobId: string,
  productId: string | null | undefined,
  runtimeType: string,
  payload: unknown
): Promise<void> {
  await queue.enqueue(
    {
      jobId,
      productId: productId ?? 'system',
      type: runtimeType,
      payload,
    },
    { jobId }
  );
}

export async function getQueueStatus(): Promise<Record<string, unknown>> {
  const repository = await getProductAiJobRepository();
  const [pending, running, health] = await Promise.all([
    repository.findJobs('system', { type: 'db_backup', statuses: ['pending'] }),
    repository.findJobs('system', { type: 'db_backup', statuses: ['running'] }),
    queue.getHealthStatus().catch(async (error: unknown) => {
      await ErrorSystem.captureException(error, {
        service: 'database-engine-db-backup-queue',
        action: 'getQueueStatus',
      });
      return {
        deliveryMode: 'inline' as const,
        workerState: 'offline' as const,
        redisAvailable: false,
        workerLocal: false,
        waitingCount: 0,
        activeCount: 0,
        completedCount: 0,
        failedCount: 0,
        running: false,
        healthy: false,
        processing: false,
      };
    }),
  ]);
  return {
    name: DATABASE_BACKUP_QUEUE_NAME,
    ...health,
    waitingCount: pending.length,
    activeCount: running.length,
    repositoryPendingCount: pending.length,
    repositoryRunningCount: running.length,
  };
}

import { NextResponse, type NextRequest } from 'next/server';

import {
  ADMIN_LAYOUT_SESSION_HEADER,
  buildAdminLayoutSessionHeaderValue,
} from '@/shared/lib/auth/admin-layout-session';
import { CSRF_COOKIE_NAME, ensureCsrfCookie } from '@/shared/lib/security/csrf';

import { authConfig } from './auth/server/auth.config';
import { auth } from './auth/server/edge';

import type { Session } from 'next-auth';

type NextRequestHandler = NonNullable<typeof handler>;
type HandlerContext = Parameters<NextRequestHandler>[1];
type AuthenticatedProxyRequest = NextRequest & { auth?: Session | null };

const DATABASE_ADMIN_PREFIX = '/admin/databases';

const finalizeResponse = (request: NextRequest, response: NextResponse): NextResponse => {
  const existing = request.cookies.get(CSRF_COOKIE_NAME)?.value ?? null;
  ensureCsrfCookie(response, existing);
  return response;
};

const baseProxy = (request: NextRequest, requestHeaders?: Headers): NextResponse => {
  const response = requestHeaders
    ? NextResponse.next({ request: { headers: requestHeaders } })
    : NextResponse.next();
  return finalizeResponse(request, response);
};

const isDatabaseAdminRequest = (pathname: string): boolean =>
  pathname === DATABASE_ADMIN_PREFIX ||
  pathname.startsWith(`${DATABASE_ADMIN_PREFIX}/`);

const isSafePageMethod = (request: NextRequest): boolean =>
  request.method === 'GET' || request.method === 'HEAD';

const buildAdminRequestHeaders = (request: AuthenticatedProxyRequest): Headers | null => {
  const sessionHeaderValue = buildAdminLayoutSessionHeaderValue(request.auth ?? null);
  if (!sessionHeaderValue) return null;

  const forwardedHeaders = new Headers(request.headers);
  forwardedHeaders.set(ADMIN_LAYOUT_SESSION_HEADER, sessionHeaderValue);
  return forwardedHeaders;
};

const buildSignInRedirect = (request: NextRequest): NextResponse => {
  const target = new URL('/auth/signin', request.url);
  target.searchParams.set('callbackUrl', `${request.nextUrl.pathname}${request.nextUrl.search}`);
  return finalizeResponse(request, NextResponse.redirect(target, 307));
};

const toMutableResponse = (response: Response): NextResponse =>
  new NextResponse(response.body, {
    status: response.status,
    statusText: response.statusText,
    headers: response.headers,
  });

const authorizeDatabaseAdminRequest = async (
  request: AuthenticatedProxyRequest
): Promise<Response | null> => {
  const authorized = authConfig.callbacks?.authorized;
  if (authorized === undefined) {
    return request.auth?.user === undefined ? buildSignInRedirect(request) : null;
  }

  const result = await authorized({
    auth: request.auth ?? null,
    request: { nextUrl: request.nextUrl },
  });

  if (result === true) return null;
  if (result instanceof Response) return finalizeResponse(request, toMutableResponse(result));
  return buildSignInRedirect(request);
};

const resolveCanonicalRedirect = (request: NextRequest): NextResponse | null => {
  if (!isSafePageMethod(request)) return null;

  const redirects = new Map<string, string>([
    ['/admin', '/admin/databases'],
  ]);
  const destination = redirects.get(request.nextUrl.pathname);
  if (!destination) return null;

  return finalizeResponse(request, NextResponse.redirect(new URL(destination, request.url), 307));
};

const handler =
  typeof auth === 'function'
    ? auth(async (request: AuthenticatedProxyRequest): Promise<Response> => {
        const fastRedirect = resolveCanonicalRedirect(request);
        if (fastRedirect) return fastRedirect;

        const authResponse = await authorizeDatabaseAdminRequest(request);
        if (authResponse) return authResponse;

        return baseProxy(request, buildAdminRequestHeaders(request) ?? undefined);
      })
    : null;

export function proxy(request: NextRequest, context?: HandlerContext): Promise<Response> | Response {
  const fastRedirect = resolveCanonicalRedirect(request);
  if (fastRedirect) return fastRedirect;

  if (!isDatabaseAdminRequest(request.nextUrl.pathname)) {
    return baseProxy(request);
  }

  if (!handler || typeof handler !== 'function') {
    return baseProxy(request);
  }

  const resolvedContext = context ?? ({ params: {} } as HandlerContext);
  const result = handler(request, resolvedContext);
  if (result instanceof Promise) {
    return result.then((response) => response ?? baseProxy(request));
  }
  return result ?? baseProxy(request);
}

export default proxy;

